const FormCtx = createContext<{ onChange: (path: string, value: unknown) => void } | null>(null);

function FormProvider({ children, onChange }: { children: React.ReactNode; onChange: (path: string, value: unknown) => void }) {
  return <FormCtx.Provider value={{ onChange }}>{children}</FormCtx.Provider>;
}

function Field({ name, value }: { name: string; value: string }) {
  const ctx = useContext(FormCtx);
  return <input value={value} onChange={(e) => ctx?.onChange(name, e.target.value)} />;
}

