function FormWithErrors() {
  const { register, handleSubmit, formState: { errors } } = useForm();
  const errorList = Object.entries(errors).map(([field, error]) => ({ field, message: error?.message as string }));
  return (
    <form onSubmit={handleSubmit(submit)}>
      {errorList.length > 0 && (
        <div role="alert" aria-live="polite" className="errors-summary">
          <h2>Please fix the following:</h2>
          <ul>
            {errorList.map(({ field, message }) => (
              <li key={field}>
                <a href={`#${field}`}>{message}</a>
              </li>
            ))}
          </ul>
        </div>
      )}
      <input id="email" {...register('email', { required: 'Email required' })} aria-invalid={!!errors.email} />
      {errors.email && <span role="alert">{errors.email.message as string}</span>}
    </form>
  );
}

