function useAnimation(onFrame: (dt: number) => void) {
  useEffect(() => {
    let frameId: number;
    let lastTime = performance.now();
    function tick(now: number) {
      if (document.hidden) {
        lastTime = now;  // skip frame, update time
        frameId = requestAnimationFrame(tick);
        return;
      }
      onFrame(now - lastTime);
      lastTime = now;
      frameId = requestAnimationFrame(tick);
    }
    frameId = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(frameId);
  }, [onFrame]);
}

